import React from 'react';
import clsx from 'clsx';
import { EmptyNeutralNoContent } from '@universe-design/illustration-react';
import type { Optional } from 'utility-types';
import { useCssScope, useLocale } from '../config-provider/hooks';
import type { IllustrationProps } from '../illustration';
import { Illustration } from '../illustration';

import './style';

export type EmptyProps = Optional<IllustrationProps, 'image'>;

export const Empty: React.FC<EmptyProps> = props => {
  const locale = useLocale();

  const { image, description = locale.components.empty.description, className, ...restProps } = props;

  const cssScope = useCssScope('empty');
  const cls = clsx(
    {
      [cssScope('--default')]: !image, // 这里 `--default` 没有相关样式绑定，只是为了兼容之前的 className
    },
    className,
  );

  const illustrationProps = {
    ...restProps,
    description,
    prefixCls: cssScope(),
    className: cls,
    image: image ?? <EmptyNeutralNoContent />,
  };

  return <Illustration {...illustrationProps} />;
};
